previewCss:
.darma-loader-darma-custom-129 {
  color: var(--loader-color, #9333ea);
width: 49px;
aspect-ratio: .75;
--c: no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color, #d8b4fe));
background:
var(--c) 0% 50%,
var(--c) 50% 50%,
var(--c) 100% 50%;
background-size: 20% 60%;
animation: darma-loader-darma-custom-129-l9 1s infinite;
}
@keyframes darma-loader-darma-custom-129-l9 {
33% {background-position: 0% 0% ,50% 100%,100% 0% }
66% {background-position: 0% 100%,50% 0% ,100% 100%}
}

